SELECT accounts.account_id, accounts.account_status, loans.loan_amount
FROM accounts
INNER JOIN loans ON accounts.account_id = loans.account_id;

SELECT withdrawal_count
FROM withdrawals
WHERE withdrawal_count = (SELECT MAX(withdrawal_count) FROM withdrawals);

SELECT DISTINCT u.full_name
FROM users u
JOIN audit_logs a ON u.owner_client_id = a.user_id;

SELECT *
FROM debit_transactions
WHERE account_id = 1;

SELECT a.account_id, a.contact_email, w.total_withdrawal
FROM accounts a
JOIN (
  SELECT account_id, SUM(max_withdrawal) AS total_withdrawal
  FROM withdrawals
  GROUP BY account_id
) w ON a.account_id = w.account_id
WHERE w.total_withdrawal > (
  SELECT AVG(max_withdrawal) FROM withdrawals
);

SELECT account_id
FROM balances
WHERE current_balance > (SELECT AVG(current_balance) FROM balances);

SELECT debit_type, AVG(debit_txn_tot) AS avg_debit_txn_tot
FROM debit_transactions
GROUP BY debit_type;

SELECT c.account_id, c.credit_type, d.debit_type
FROM credit_transactions c
INNER JOIN debit_transactions d ON c.account_id = d.account_id;

SELECT SUM(current_balance) AS total_balance
FROM balances 
WHERE account_id IN (
    SELECT account_id 
    FROM accounts 
    WHERE account_district = (
        SELECT owner_district FROM users WHERE full_name = 'Jane Smith'
    )
    AND account_id IN (
        SELECT account_id FROM credit_transactions WHERE credit_txn_ct > 50
    )
);

SELECT AVG(max_credit_amount) AS average_max_credit
FROM credit_transactions
WHERE account_id = 1;

SELECT DISTINCT preferred_language, last_activity_date
FROM accounts
WHERE last_activity_date > date('now', '-6 month') AND account_status = 'active';
